export const createSvgRendererCapabilities = (options = {}) => ({
    animation: "reactNative",
    clipPaths: true,
    gradients: true,
    hitRegions: true,
    layers: true,
    shadows: false,
    symbols: true,
    testIds: true,
    textMeasurement: options.measureText ? "custom" : "fallback",
    ...options.capabilities
});
